mapper.select:
SELECT uusdvm.modl_cd, uusdvm.modl_nm, uusdvm.stb_sw_ver, substr(uusdvm.stb_sw_rst_ver, 1, 9) as stb_sw_rst_ver, uusdvm.stm_fir_reg_date, uusdvm.stm_last_upd_date, aumfir.user_nm stm_fir_reg_user_nm, aumlst.user_nm stm_last_upd_user_nm FROM um_upd_sw_dvc_ver_map uusdvm, ad_user_mst aumfir, ad_user_mst aumlst WHERE uusdvm.stm_fir_reg_user_id = aumfir.user_id(+) AND uusdvm.stm_last_upd_user_id = aumlst.user_id(+)
AND UPPER(uusdvm.modl_nm) LIKE UPPER('%'||#{modlNm}||'%')
AND uusdvm.stb_sw_ver BETWEEN #{toVersion} AND #{fromVersion}
AND uusdvm.stb_sw_ver like #{toVersion}||'%'
AND uusdvm.stb_sw_ver >= #{toVersion}
AND uusdvm.stb_sw_ver <= #{toVersion}
ORDER BY uusdvm.modl_nm, uusdvm.stb_sw_ver

SELECT
  *
FROM
  um_upd_sw_dvc_ver_map uusdvm

  uusdvm.modl_nm = #{modlNm}
  AND uusdvm.stb_sw_ver = #{stbSwVer}
